'use strict';document.addEventListener('DOMContentLoaded',function(){(function(){const verticalExample=document.getElementById('vertical-example'),horizontalExample=document.getElementById('horizontal-example'),horizVertExample=document.getElementById('both-scrollbars-example');if(verticalExample){new PerfectScrollbar(verticalExample,{wheelPropagation:!1})}
if(horizontalExample){new PerfectScrollbar(horizontalExample,{wheelPropagation:!1,suppressScrollY:!0})}
if(horizVertExample){new PerfectScrollbar(horizVertExample,{wheelPropagation:!1})}})()})